<template>
  <div class="istaproductdetail">
    <van-sticky>
      <van-nav-bar title="委托单详情" left-arrow @click-left="onClickLeft" />
    </van-sticky>
    <main class="detail">
      <h1>
        委托单编号: <span style="color: #1989fa">{{ entrustNumber }}</span>
      </h1>
      <hr style="border: 1px dashed #1989fa" />
      <van-row>
        <van-col span="12">
          <span
            >委托方式：{{
              detail.entrustType == 1
                ? "客户委托"
                : detail.entrustType == 2
                ? "内部委托"
                : "科研"
            }}</span
          >
          <span>委托人：{{ detail.entrustPeople }}</span>
          <span>联系电话：{{ detail.entrustPeoplePhone }}</span>
          <span>见证人：{{ detail.witnessPeople }}</span>
        </van-col>
        <van-col span="12">
          <span>检验目的：{{ detail.checkPurpose }}</span>
          <span>取样方式：{{ detail.sampleReceiveWay }}</span>
          <span>取报告方式：{{ detail.reportGetWay }}</span>
          <span>报告份数：{{ detail.reportNum }}</span>
        </van-col>
      </van-row>
      <van-row>
        <van-col span="12">
          <span>委托单位：{{ detail.comName }}</span>
          <span>见证单位：{{ detail.witnessCompanyName }}</span>
          <span>工程名称：{{ detail.projectId }}</span>

          <span>工程部位：{{ detail.projectPart }}</span>

          <!-- <span>备注：{{ detail.entrustNote }}</span> -->
        </van-col>
      </van-row>
      <hr style="border: 1px dashed #1989fa" />

      <ul>
        <li v-for="(item, i) in detail.sampleList" :key="i">
          <div>
            <h1>样品名称：{{item.productName}}</h1>
            <main>
              <p>样品批次：{{item.objectCount}}</p>
              <p>产品规格:{{item.productName}}</p>
              <p>样品数量：{{item.productNumber}}</p>
              <p>生产厂家：{{item.productCompanyName}}</p>
              <p>检验项目：<span v-for="(item1,i) in item.checkList" :key="i">{{item1.checkItemName}}、</span></p>
              <p>判定依据：{{item.productStandardSource}}</p>
            </main>
          </div>
        </li>
      </ul>
    </main>
  </div>
</template>

<script>
import { getistas } from "../../utils/http/api";
import { deepClone } from "../../utils/deppClone";
export default {
  name: "Istaproductdetail",
  data() {
    return {
      entrustNumber: "",
      detail: "",
      list: [1, 23, 45, 5, 6, 5, 5, 5],
    };
  },
  created() {
    this.entrustNumber = this.$route.query.entrustId;
    this.init(this.entrustNumber);
  },
  methods: {
    init(entrustId) {
      getistas(entrustId).then((res) => {
        // console.log(res);
        this.detail = deepClone(res.data.data);
      });
    },
    onClickLeft() {
      this.$router.go(-1);
    },
  },
};
</script>


<style lang="less">
.istaproductdetail {
  width: 7.5rem;
  .detail {
    padding: 10px;

    hr {
      margin-top: 10px;
    }
    h1 {
      font-size: 18px;
    }
    .van-col--12 {
      display: flex;
      flex-direction: column;
      padding: 5px;
      span {
        font-size: 14px;
        margin-top: 5px;
      }
    }
  }
  ul > li {
    display: flex;
    border-radius: 10px;
    background: @gray-1;
    margin-top: 10px;

    > div {
      padding: 10px;
      box-sizing: border-box;
      h1 {
        font-size: 15px !important;
        // font-weight: 400;
      }
    }

    main {
      padding: 10px;
      box-sizing: border-box;
      p {
        font-size: 14px;
      }
    }
  }
}
</style>